import{_ as a}from"./chunks/xuanji-cover.CaJrYJ75.js";import{_ as r,o as d,c as e,ai as o}from"./chunks/framework.DyvBZb4W.js";const m=JSON.parse('{"title":"玄羁 人物 Mod","description":"","frontmatter":{},"headers":[],"relativePath":"mods/xuanji-character/index.md","filePath":"mods/xuanji-character/index.md","lastUpdated":1780733792000}'),i={name:"mods/xuanji-character/index.md"};function l(n,t,s,h,c,g){return d(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="玄羁-人物-mod" tabindex="-1">玄羁 人物 Mod <a class="header-anchor" href="#玄羁-人物-mod" aria-label="Permalink to &quot;玄羁 人物 Mod&quot;">​</a></h1><p>玄羁是一个男性《杀戮尖塔2》自定义角色 Mod。他把战斗拆成“出牌、纳编、凝核、成型”的节奏：带羁绊的牌打出后进入机匣，机匣集齐 3 张牌时凝成机核，机核上的羁绊会在后续回合持续推动牌组节奏。</p><figure><img src="'+a+'" alt="玄羁人物 Mod 封面"><figcaption>纳编 · 凝核 · 羁绊。</figcaption></figure><p>当前版本：<code>0.10.0-beta</code><br> 发布状态：Beta<br> 作者：Jason Song<br> 类型：自定义角色 / 羁绊构筑 / 机核规划<br> 是否影响玩法：是，会加入新角色、专属卡牌、专属遗物和新的构筑方向。</p><h2 id="玩法概览" tabindex="-1">玩法概览 <a class="header-anchor" href="#玩法概览" aria-label="Permalink to &quot;玩法概览&quot;">​</a></h2><p>玄羁不是围绕单张大牌爆发设计的角色。他的核心乐趣在于先用带标签的牌铺设方向，再通过纳编和凝核把这些标签固定成机核，最后让不同羁绊在回合开始、纳编、凝核、抽牌、消耗、战斗胜利等时机互相触发。</p><ul><li><strong>纳编</strong>：带纳编的牌打出后进入机匣；已经纳编的牌本场战斗不会再次贡献羁绊。</li><li><strong>机匣</strong>：临时保存待凝核的牌。机匣顺序会影响下一次凝核结果，因此调度机匣本身也是决策的一部分。</li><li><strong>凝核</strong>：机匣集齐 3 张牌时凝成机核。机核提供羁绊进度，也可能带来对应的主标签身份。</li><li><strong>变阵</strong>：部分牌可以移动、移除、替换或追加标签，让你修正即将凝出的机核，而不是只能被动等待。</li><li><strong>蓄势成长</strong>：部分路线会把战斗内规划转化为金币、最大生命、牌库升级、重放或后续战斗增益。</li></ul><p>一局游戏里，你通常不会追求所有羁绊全满。更常见的选择是先判断当前牌组需要防守、爆发、抽牌、能量、消耗、中毒/负面状态、长期成长，还是多羁绊联动，然后围绕这些方向挑牌和调整凝核顺序。</p><h2 id="主要羁绊" tabindex="-1">主要羁绊 <a class="header-anchor" href="#主要羁绊" aria-label="Permalink to &quot;主要羁绊&quot;">​</a></h2><p>当前版本共有 8 个羁绊。下面只概括方向，不列出全部卡牌细节。</p><table tabindex="0"><thead><tr><th>羁绊</th><th>方向</th><th>主要效果</th></tr></thead><tbody><tr><td>固守</td><td>防守、格挡成长</td><td>固守机核会在回合开始提供格挡；羁绊进度提高后，获得格挡时追加格挡，高进度可以保留格挡并反弹受到的攻击伤害。</td></tr><tr><td>突袭</td><td>攻击节奏、爆发</td><td>突袭机核强化每回合第一次攻击；羁绊进度提高后获得活力、临时力量，并能生成额外攻击牌。</td></tr><tr><td>推演</td><td>抽牌、手牌过滤</td><td>推演机核在纳编时补牌；羁绊进度提高后提供回合开始抽牌、纳编后抽牌、弃牌/消耗选择，最终可把抽牌转化为群体伤害。</td></tr><tr><td>超载</td><td>能量、蓄能爆发</td><td>超载机核在凝核后提供能量；高进度后获得额外能量、保留未用能量，并能把当前能量转化为全体伤害。</td></tr><tr><td>蓄势</td><td>长期收益、战斗外成长</td><td>蓄势机核在未凝核的回合提供金币；高进度后胜利时提高最大生命、升级牌库或添加重放，并通过蓄势纹章带来后续战斗加成。</td></tr><tr><td>转化</td><td>消耗、资源循环</td><td>转化机核让消耗转化为抽牌；羁绊进度提高后，纳编和消耗会带来抽牌、能量与 0 费消耗随机牌。</td></tr><tr><td>蚀刻</td><td>中毒、虚弱、易伤</td><td>蚀刻机核在回合开始给敌人叠加中毒；高进度后追加虚弱、易伤，覆盖更多敌人，并在终局阶段提供大量中毒。</td></tr><tr><td>协同</td><td>多羁绊触发器</td><td>协同机核在其他主机核触发时提供格挡；高进度后会在其他羁绊触发时给格挡、抽牌、能量或伤害，并提高整体羁绊进度。</td></tr></tbody></table><h2 id="构筑方向" tabindex="-1">构筑方向 <a class="header-anchor" href="#构筑方向" aria-label="Permalink to &quot;构筑方向&quot;">​</a></h2><p>玄羁的构筑更像“规划一套运行系统”而不是只找一张核心牌。常见方向包括：</p><ul><li>用 <strong>固守 + 推演</strong> 稳定防守、抽牌和回合质量。</li><li>用 <strong>突袭 + 超载</strong> 把能量和首攻加成转成快速击杀。</li><li>用 <strong>转化 + 推演</strong> 围绕抽牌、消耗和 0 费资源滚动。</li><li>用 <strong>蚀刻 + 蓄势</strong> 走持续压制和长期成长。</li><li>用 <strong>协同</strong> 串起多个已成型羁绊，让每次触发都带来额外收益。</li></ul><h2 id="兼容说明" tabindex="-1">兼容说明 <a class="header-anchor" href="#兼容说明" aria-label="Permalink to &quot;兼容说明&quot;">​</a></h2><ul><li>需要安装 <code>BaseLib v3.1.0</code>。</li><li>当前版本按《杀戮尖塔2》<code>v0.103</code> 正式版和 <code>v0.107</code> beta 版做过兼容处理。</li><li>这是 Beta 版本，数值、卡池和 UI 仍可能根据反馈继续调整。</li></ul><h2 id="链接" tabindex="-1">链接 <a class="header-anchor" href="#链接" aria-label="Permalink to &quot;链接&quot;">​</a></h2><ul><li>B 站介绍视频：<a href="https://www.bilibili.com/video/BV1mxV96wEca/" target="_blank" rel="noreferrer">玄羁人物 Mod 介绍</a></li><li>返回：<a href="/jasonsong-games/mods/">全部 Mod</a></li></ul>',18)])])}const b=r(i,[["render",l]]);export{m as __pageData,b as default};
